changeSet.sql:
update sector_association_scheme
set scheme_version = 'CCA_2';
update subsector_association_scheme
set scheme_version = 'CCA_2';


update sector_association_scheme_document
set file_name = 'Umbrella Agreement (' || replace(file_name, '_umbrella_agreement', ')')
where file_name like '%_umbrella_agreement%';

update sector_association_scheme_document
set file_name = replace(file_name, 'Umbrella Agreement', 'Umbrella Agreement CCA2');

insert into target_commitment (id, target_period, target_improvement, target_set_id) select nextval('target_commitment_id_seq'), 'TP7 (2026)', 0 , ts.id from target_set ts where is_cca3 = 1;
insert into target_commitment (id, target_period, target_improvement, target_set_id) select nextval('target_commitment_id_seq'), 'TP8 (2027-2028)', 0 , ts.id from target_set ts where is_cca3 = 1;
insert into target_commitment (id, target_period, target_improvement, target_set_id) select nextval('target_commitment_id_seq'), 'TP9 (2029-2030)', 0 , ts.id from target_set ts where is_cca3 = 1;

alter table target_set
drop column sector_id, 
drop column subsector_id, 
drop column is_cca3;

alter table sector_association_scheme_document
drop column sector_id;
